package com.sdw.music.player.util

/**
 * Lightweight Chinese → Pinyin initial for A-Z indexing.
 * Covers ~5500 most common CJK characters; unknown → '#'.
 */
object PinyinUtils {
    private const val FALLBACK = '#'

    fun getInitial(ch: Char): Char = when {
        ch in 'A'..'Z' -> ch
        ch in 'a'..'z' -> ch.uppercaseChar()
        ch.code in 0x4E00..0x9FFF -> PINYIN_MAP[ch] ?: FALLBACK
        else -> FALLBACK
    }

    fun getInitial(s: String): Char = s.firstOrNull()?.let { getInitial(it) } ?: FALLBACK

    private val PINYIN_MAP: Map<Char, Char> by lazy { decodeGroups() }

    private fun decodeGroups(): Map<Char, Char> {
        val groups = PINYIN_DATA.split('|')
        val map = HashMap<Char, Char>(groups.sumOf { it.length } + 26)
        for (i in groups.indices) {
            val initial = 'A' + i
            for (ch in groups[i]) { map[ch] = initial }
        }
        return map
    }

